import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

// Import your pages
import HospitalListing from "./pages/HospitalListing.jsx";
import DoctorsList from "./pages/DoctorsList.jsx";
import DoctorProfile from "./pages/DoctorProfile.jsx";
import AdminDashboard from "./pages/AdminDashboard.jsx";

// Import Navbar (make sure file is src/components/Navbar.jsx)
import Navbar from "./components/Navbar";

function App() {
  return (
    <Router>
      <div style={{ backgroundColor: "#f5f5f5", minHeight: "100vh" }}>
        {/* Navbar goes here — shows on EVERY page */}
        <Navbar />

        {/* All routes */}
        <Routes>
          {/* Home / Hospital Listing */}
          <Route path="/" element={<HospitalListing />} />

          {/* Doctors list for a hospital */}
          <Route
            path="/hospital/:hospitalId/doctors"
            element={<DoctorsList />}
          />




          {/* Single doctor profile + booking */}
          <Route path="/doctor/:doctorId" element={<DoctorProfile />} />

          {/* Admin Dashboard */}
          <Route path="/admin/dashboard" element={<AdminDashboard />} />

          {/* 404 - catch-all */}
          <Route
            path="*"
            element={
              <div style={{ textAlign: "center", padding: "100px 20px" }}>
                <h2>Page Not Found</h2>
                <p>Sorry, the page you're looking for doesn't exist.</p>
              </div>
            }
          />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
